@* Reusable textarea + button for sending messages or replies *@

<div class="message-input">
    <textarea class="message-input__textarea"
              placeholder="@Placeholder"
              @bind="text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="message-input__button" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    private string text = string.Empty;

    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var message = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(message);
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input__textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input__textarea:focus {
    border-color: #4a76a8;
}

.message-input__button {
    align-self: flex-end;
    padding: 8px 20px;
    background: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.message-input__button:hover:not(:disabled) {
    background: #3b6291;
}

.message-input__button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<div class="reaction-bar">
    @foreach (var reaction in Reactions)
    {
        <button class="reaction-badge" @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)"
                title="@string.Join(", ", reaction.Users)">
            <span>@reaction.Emoji</span>
            <span class="reaction-badge__count">@reaction.Users.Count</span>
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Reaction> Reactions { get; set; } = [];
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f5f5f5;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e8e8e8;
    border-color: #ccc;
}

.reaction-badge__count {
    font-size: 12px;
    color: #666;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    padding: 6px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    position: absolute;
    bottom: 100%;
    right: 0;
    z-index: 10;
}

.emoji-picker__item {
    border: none;
    background: transparent;
    font-size: 18px;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    transition: background 0.15s;
}

.emoji-picker__item:hover {
    background: #f0f0f0;
}

