    font-weight: 700;
    font-size: 15px;
    color: #1a1a1a;
}

.message-item__time {
    font-size: 12px;
    color: #999;
}

.message-item__content {
    font-size: 14px;
    line-height: 1.5;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
