    display: inline-block;
    margin-top: 4px;
    padding: 2px 0;
    border: none;
    background: none;
    color: #4a76a8;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
}

.message-item__thread-link:hover {
    text-decoration: underline;
}

.message-item__actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.08);
