    border: none;
    background: transparent;
    font-size: 16px;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-item__action-btn:hover {
    background: #f0f0f0;
}

.message-item__react-wrapper {
    position: relative;
}

