arguments.file_text:
@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<aside class="channel-sidebar">
    <div class="channel-sidebar__header">
        <h2 class="channel-sidebar__title">Channels</h2>
    </div>
    <div class="channel-sidebar__list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</aside>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    background: #2c3e50;
    color: #ecf0f1;
    overflow: hidden;
}

.channel-sidebar__header {
    padding: 16px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.channel-sidebar__title {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
}

.channel-sidebar__list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<div class="message-list" @onscroll="HandleScroll" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="message-list__loader">Loading older messages…</div>
    }

    @foreach (var message in Messages)
    {
        var isThreadStarter = message.ReplyToId is null && ThreadSummaries.TryGetValue(message.Id, out var summary);
        var replyCount = isThreadStarter ? summary!.ReplyCount : 0;

        <MessageItem Message="message"
                     IsThreadStarter="isThreadStarter"
                     ReplyCount="replyCount"
                     OnOpenThread="OnOpenThread"
                     OnAddReaction="OnAddReaction" />
    }

    @if (Messages.Count == 0 && !IsLoadingMore)
    {
        <div class="message-list__empty">No messages yet. Start the conversation!</div>
    }
</div>

@code {
    private ElementReference scrollContainer;

    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnAddReaction { get; set; }

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.message-list__loader {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 13px;
}

.message-list__empty {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 15px;
}

@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<section class="message-area">
    @if (Channel is not null)
