    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-panel__header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
}

.thread-panel__title {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.thread-panel__close {
    border: none;
    background: transparent;
    font-size: 18px;
    cursor: pointer;
    color: #999;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.15s, color 0.15s;
}

.thread-panel__close:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-panel__root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f9f9f9;
}

.thread-panel__root-author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a1a;
    margin-bottom: 4px;
}

.thread-panel__root-content {
    font-size: 14px;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-panel__replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-panel__reply {
    padding: 8px 16px;
}

.thread-panel__reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.thread-panel__reply-author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a1a;
}

.thread-panel__reply-time {
    font-size: 12px;
    color: #999;
}

.thread-panel__reply-content {
    font-size: 14px;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-panel__no-replies {
    padding: 24px 16px;
    text-align: center;
    color: #999;
    font-size: 14px;
}
