@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<section class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area__header">
            <h2 class="message-area__channel-name"># @Channel.Name</h2>
            <span class="message-area__channel-desc">@Channel.Description</span>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     IsLoadingMore="IsLoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnOpenThread="OnOpenThread"
                     OnAddReaction="OnAddReaction" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSend="OnSendMessage" />
    }
    else
    {
        <div class="message-area__placeholder">
            Select a channel to start chatting
        </div>
    }
</section>

@code {
