@using sv_801412bc71f44d4e942bc46e75a21c48.Services

<aside class="thread-panel">
    <div class="thread-panel__header">
        <h3 class="thread-panel__title">Thread</h3>
        <button class="thread-panel__close" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-panel__root-message">
            <div class="thread-panel__root-author">@RootMessage.Author</div>
            <div class="thread-panel__root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-panel__replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-panel__reply">
                    <div class="thread-panel__reply-header">
                        <span class="thread-panel__reply-author">@reply.Author</span>
                        <span class="thread-panel__reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="thread-panel__reply-content">@reply.Content</div>
                </div>
            }

            @if (Replies.Count == 0)
            {
                <div class="thread-panel__no-replies">No replies yet</div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</aside>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

