arguments.file_text:
@page "/chat"
@using sv_801412bc71f44d4e942bc46e75a21c48.Services
@rendermode InteractiveServer
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-page">
    <div class="chat-page__sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-page__main @(activeThreadId.HasValue ? "" : "chat-page__main--wide")">
        <MessageArea Channel="ActiveChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadOlderMessages"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnAddReaction="AddReaction" />
    </div>

    @if (activeThreadId.HasValue && threadRootMessage is not null)
    {
        <div class="chat-page__thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private int activeChannelId;
    private int? activeThreadId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private CancellationTokenSource cts = new();

    private Channel? ActiveChannel => channels.FirstOrDefault(c => c.Id == activeChannelId);

    [Inject] private IChatService ChatService { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (channelId == activeChannelId) return;

        activeChannelId = channelId;
        messages = [];
        hasMoreMessages = true;
        threadSummaries = [];
        CloseThread();

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count == PageSize;

        await BuildThreadSummaries();

        _ = ChatService.MarkChannelReadAsync(channelId);
        UpdateUnreadCount(channelId);
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);

        await BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var message = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(message);
    }

    private async Task OpenThread(int messageId)
    {
        activeThreadId = messageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        activeThreadId = null;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeThreadId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, content, activeThreadId.Value);
        threadReplies.Add(reply);

        // Update thread summary in main message list
        if (threadSummaries.ContainsKey(activeThreadId.Value))
        {
            var existing = threadSummaries[activeThreadId.Value];
            threadSummaries[activeThreadId.Value] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[activeThreadId.Value] = new ThreadSummary(activeThreadId.Value, 1, reply.SentAt);
        }
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the UI
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task BuildThreadSummaries()
    {
        // Build summaries from messages that have replies referencing them
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            if (!threadSummaries.ContainsKey(rootId))
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                if (thread.Count > 0)
                {
                    threadSummaries[rootId] = new ThreadSummary(
                        rootId,
                        thread.Count,
                        thread.Max(t => t.SentAt));
                }
            }
        }
    }

    private void UpdateUnreadCount(int channelId)
    {
        var index = channels.FindIndex(c => c.Id == channelId);
        if (index >= 0)
        {
            channels[index] = channels[index] with { UnreadCount = 0 };
        }
    }

    public ValueTask DisposeAsync()
    {
        cts.Cancel();
        cts.Dispose();
        return ValueTask.CompletedTask;
    }
}

.chat-page {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-page__sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-page__main {
    width: 55%;
    flex-grow: 1;
    min-width: 0;
    transition: width 0.2s ease;
}

.chat-page__main--wide {
    width: 80%;
}

.chat-page__thread {
    width: 25%;
    min-width: 280px;
    flex-shrink: 0;
}

